/**
 * This script creates a pull request with verified commits for any pending changes.
 * It is designed to be run in a GitHub Actions workflow.
 *
 * It performs the following steps:
 * 1. Checks for any uncommitted changes in the git repository.
 * 2. If no changes are found, it exits gracefully.
 * 3. If changes are found, it creates a new branch.
 * 4. It then creates blobs and a tree for the changed files using the GitHub API.
 * 5. It creates a new commit, which will be verified as it's created via the API.
 * 6. It updates the branch reference to point to the new commit.
 * 7. Finally, it creates a pull request for the new branch.
 */
export default async ({ github, context, exec, core }) => {
  const branchName = 'automation/update-go-deps';
  const commitMessage = 'chore(main): update go dependencies';
  const prTitle = 'chore(main): update go dependencies';
  const prBody = `Automated Go dependency updates.
This PR is generated by the \`update-go-deps\` workflow.`;

  // 1. Check for changes
  let gitStatus = '';
  await exec('git', ['status', '--porcelain'], {
    listeners: {
      stdout: (data) => {
        gitStatus += data.toString();
      },
    },
  });

  if (gitStatus.trim() === '') {
    core.info('No changes detected. Skipping PR creation.');
    return;
  }

  core.info('Changes detected. Creating a verified commit and PR...');
  const changedFiles = gitStatus.trim().split('\n').map(line => line.substring(3));

  try {
    const owner = context.repo.owner;
    const repo = context.repo.repo;
    const baseBranch = context.payload.repository.default_branch;

    // 2. Get base branch details
    const { data: baseBranchData } = await github.rest.repos.getBranch({
      owner,
      repo,
      branch: baseBranch,
    });
    const baseCommitSha = baseBranchData.commit.sha;
    const baseTreeSha = baseBranchData.commit.commit.tree.sha;

    // 3. Create blobs for each changed file
    const createBlobPromises = changedFiles.map(async (filePath) => {
      const { stdout: content } = await execAndGetStdout(exec, 'git', ['show', `:${filePath}`]);
      const { data: blobData } = await github.rest.git.createBlob({
        owner,
        repo,
        content,
        encoding: 'utf-8',
      });
      return { path: filePath, sha: blobData.sha, mode: '100644', type: 'blob' };
    });

    const treeItems = await Promise.all(createBlobPromises);

    // 4. Create a new tree
    const { data: treeData } = await github.rest.git.createTree({
      owner,
      repo,
      base_tree: baseTreeSha,
      tree: treeItems,
    });

    // 5. Create a new commit
    const { data: commitData } = await github.rest.git.createCommit({
      owner,
      repo,
      message: commitMessage,
      tree: treeData.sha,
      parents: [baseCommitSha],
    });

    // 6. Create or update the branch
    try {
      await github.rest.git.createRef({
        owner,
        repo,
        ref: `refs/heads/${branchName}`,
        sha: commitData.sha,
      });
    } catch (error) {
      // If the ref already exists, update it
      if (error.status === 422) {
        await github.rest.git.updateRef({ owner, repo, ref: `heads/${branchName}`, sha: commitData.sha });
      } else {
        throw error;
      }
    }

    // 7. Create the pull request
    await github.rest.pulls.create({ owner, repo, title: prTitle, head: branchName, base: baseBranch, body: prBody });

    core.info(`Successfully created/updated PR for branch ${branchName}.`);
  } catch (error) {
    core.setFailed(`Failed to create pull request: ${error.message}`);
  }
};

async function execAndGetStdout(exec, command, args) {
  let output = '';
  const options = {
    listeners: {
      stdout: (data) => {
        output += data.toString();
      },
    },
  };
  await exec(command, args, options);
  return { stdout: output.trim() };
}
